#include<iostream>#include<vector>#define ll long longusing namespace std;int main(){    ios_base::sync_with_stdio(false);    cin.tie(NULL);    int t;    cin>>t;    while(t--){        int n;        cin>>n;        vector<ll>a(n);        ll total_even=0,even_idx=0;        ll total_odd=0,odd_idx=0;        for(int i=0;i<n;i++){            cin>>a[i];            if(i%2==0){                total_even+=a[i];                even_idx++;            }            else {                total_odd+=a[i];                odd_idx++;            }        }        ll total= total_even + total_odd;        if(total%n!=0){            cout<<"no\n";        }        else{            ll k= total/n;                        if((even_idx*k)==total_even && (odd_idx*k)==total_odd){                cout<<"yes\n";            }            else{                cout<<"no\n";            }        }    }}